const raw = $input.first().json;
const signals = Array.isArray(raw) ? raw : (raw && raw.id ? [raw] : []);
if (signals.length === 0) {
  return [{ json: { _empty: true, reason: 'no_unclassified_signals' } }];
}
return signals.map(function (s) { return { json: { signal: s } }; });

// Parse + validate Claude classification.
const ctx = $('Build Claude Prompt').item.json;
const resp = $input.item.json || {};
let textOut = null;
try { textOut = (resp.content && resp.content[0] && resp.content[0].text) || null; } catch (e) {}
const tokens = (resp.usage && (resp.usage.input_tokens + resp.usage.output_tokens)) || 0;

if (!textOut) {
  return { json: {
    signal_id: ctx.signal_id, client_id: ctx.client_id,
    _failed: true, error: 'no_text_in_response', tokens: tokens
  } };
}

const cleaned = String(textOut).replace(/```json|```/g, '').trim();
let parsed = null;
try { parsed = JSON.parse(cleaned); } catch (e) {
  return { json: {
    signal_id: ctx.signal_id, client_id: ctx.client_id,
    _failed: true, error: 'parse_error', raw_text: cleaned.slice(0, 300), tokens: tokens
  } };
}

const validCategories = ['personal','business','industry','sports','news','social','vertical_specific','financial','geographic','calendar'];
const validSensitivity = ['low','medium','high'];

const category = validCategories.indexOf(parsed.signal_category) >= 0 ? parsed.signal_category : 'business';
const sensitivity = validSensitivity.indexOf(parsed.sensitivity_level) >= 0 ? parsed.sensitivity_level : 'low';
const relevance = Math.min(Math.max(parseInt(parsed.relevance_score) || 0, 0), 100);

return { json: {
  signal_id: ctx.signal_id,
  client_id: ctx.client_id,
  lead_id: ctx.lead_id,
  signal_category: category,
  sensitivity_level: sensitivity,
  relevance_score: relevance,
  recommended_archetype: parsed.recommended_archetype || null,
  rationale: parsed.rationale || null,
  tokens: tokens,
  needs_review: sensitivity === 'high'
} };
